import React from 'react';

export function KPI({ title, value, color = '#0D1117', subtitle }) {
  return (
    <div style={{ background: '#fff', padding: 16, borderRadius: 12, border: '1px solid #DDE3E9', boxShadow: '0 1px 3px rgba(0,0,0,0.02)' }}>
      <div style={{ fontSize: 11, textTransform: 'uppercase', color: '#7A8FA6', fontWeight: 700, letterSpacing: '0.5px' }}>{title}</div>
      <div style={{ fontSize: 24, fontWeight: 800, color, margin: '4px 0' }}>{value}</div>
      {subtitle && <div style={{ fontSize: 11, color: '#546E7A' }}>{subtitle}</div>}
    </div>
  );
}

export function Alert({ children, type = 'blue' }) {
  const bg = type === 'red' ? '#FFEBEE' : type === 'green' ? '#E8F5E9' : '#E3F2FD';
  const co = type === 'red' ? '#C62828' : type === 'green' ? '#2E7D32' : '#1565C0';
  return (
    <div style={{ background: bg, color: co, padding: 12, borderRadius: 8, fontSize: 12.5, fontWeight: 600, border: `1px solid ${co}22` }}>
      {children}
    </div>
  );
}
